INSERT INTO `briefs` VALUES ('brief-8dfc94ee', '2026-05-28', '[{\"id\": \"tn-1\", \"rank\": 1, \"tags\": [\"????\", \"???\", \"金融\", \"AI??\"], \"title\": \"科技与产业新政\", \"source\": [\"????\", \"???\", \"金融\", \"AI??\"], \"summary\": \"分析完成。\", \"hotIndex\": 100, \"publishedAt\": \"2026-05-28\"}, {\"id\": \"tn-2\", \"rank\": 2, \"tags\": [\"????\", \"???\", \"金融\", \"AI??\"], \"title\": \"科技与产业新政\", \"source\": [\"????\", \"???\", \"金融\", \"AI??\"], \"summary\": \"# 科技与产业新政  \\n*生成时间：2026-05-28T10:52:18.268391*\\n\\n---\\n\\n## 一、事件背景  \\n\\n### 事件起因与历史脉络  \\n当前科技与产业政策演进呈现“双轨驱动”特征：一方面，地缘政治博弈持续重塑全球技术供应链安全逻辑（如伊朗资产解冻谈判折射出制裁工具对高科技产业融资渠道的结构性压制）；另一方面，国内产业自主化进程加速深化，从芯片设计（比亚迪自研芯片）、存储制\", \"hotIndex\": 95, \"publishedAt\": \"2026-05-28\"}, {\"id\": \"tn-3\", \"rank\": 3, \"tags\": [\"????\", \"???\", \"金融\", \"AI??\"], \"title\": \"科技与产业新政\", \"source\": [\"????\", \"???\", \"金融\", \"AI??\"], \"summary\": \"# 科技与产业新政\\n\\n## 一、事件背景\\n\\n### 事件起因与历史脉络  \\n当前科技与产业政策环境正处于多重结构性变革交汇点：一方面，全球地缘政治博弈持续重塑技术主权边界（如伊朗资产冻结问题折射出金融制裁与技术脱钩的联动性）；另一方面，中国在半导体、人工智能、新能源智能网联等关键领域加速推进自主可控战略。2023年以来，美国对华先进制程设备出口管制升级、《芯片与科学法案》落地实施，倒逼国内企业加快\", \"hotIndex\": 90, \"publishedAt\": \"2026-05-28\"}, {\"id\": \"tn-4\", \"rank\": 4, \"tags\": [\"央行\", \"芯片\", \"政策\", \"监管\", \"AI\", \"半导体\", \"电池\", \"电动汽车\", \"利率\", \"GDP\", \"新能源\", \"出海\", \"供应链\", \"金融\", \"PMI\", \"台积电\", \"芯片管制\", \"CPI\"], \"title\": \"科技与投资动态\", \"source\": [\"央行\", \"芯片\", \"政策\", \"监管\", \"AI\", \"半导体\", \"电池\", \"电动汽车\", \"利率\", \"GDP\", \"新能源\", \"出海\", \"供应链\", \"金融\", \"PMI\", \"台积电\", \"芯片管制\", \"CPI\"], \"summary\": \"# 科技与投资动态\\n\\n## 一、事件背景\\n- **事件起因与历史脉络**\\n  - 比亚迪自研芯片的传闻引发了市场广泛关注。比亚迪作为中国领先的新能源汽车制造商，近年来在智能化和电动化方面持续加大投入。此次发布会可能标志着比亚迪在芯片领域的重大突破。\\n  - 香港政府正在积极推动金融和科技产业的发展，特别是在人工智能（AI）领域。香港投资推广署希望通过一系列措施激活黄金财富生态，吸引更多的国际资本和\", \"hotIndex\": 85, \"publishedAt\": \"2026-05-28\"}, {\"id\": \"tn-5\", \"rank\": 5, \"tags\": [\"央行\", \"芯片\", \"政策\", \"监管\", \"AI\", \"半导体\", \"电池\", \"电动汽车\", \"利率\", \"GDP\", \"新能源\", \"出海\", \"供应链\", \"金融\", \"PMI\", \"台积电\", \"芯片管制\", \"CPI\"], \"title\": \"科技与投资动态\", \"source\": [\"央行\", \"芯片\", \"政策\", \"监管\", \"AI\", \"半导体\", \"电池\", \"电动汽车\", \"利率\", \"GDP\", \"新能源\", \"出海\", \"供应链\", \"金融\", \"PMI\", \"台积电\", \"芯片管制\", \"CPI\"], \"summary\": \"# 科技与投资动态\\n\\n## 一、事件背景\\n- **事件起因与历史脉络**\\n  - 比亚迪自研芯片的传闻引发了市场广泛关注。比亚迪作为中国领先的新能源汽车制造商，近年来在智能化和电动化领域不断加大投入，自主研发芯片是其战略布局的重要一步。[来源1]\\n  - 香港政府正在积极推动金融科技创新，特别是在人工智能（AI）领域，以提升香港在全球金融市场的竞争力。[来源4]\\n  - 日本政府支持的JIC考虑出\", \"hotIndex\": 80, \"publishedAt\": \"2026-05-28\"}]', '[{\"id\": \"report-49c88660\", \"title\": \"科技与产业新政\", \"summary\": \"分析完成。\", \"sections\": [\"事件背景\", \"现状分析\", \"趋势研判\", \"风险提示\"], \"importance\": 5, \"generatedAt\": \"刚刚\", \"sourceCount\": 0}, {\"id\": \"report-ab61539a\", \"title\": \"科技与产业新政\", \"summary\": \"# 科技与产业新政  \\n*生成时间：2026-05-28T10:52:18.268391*\\n\\n---\\n\\n## 一、事件背景  \\n\\n### 事件起因与历史脉络  \\n当前科技与产业政策演进呈现“双轨驱动”\", \"sections\": [\"事件背景\", \"现状分析\", \"趋势研判\", \"风险提示\"], \"importance\": 5, \"generatedAt\": \"刚刚\", \"sourceCount\": 0}, {\"id\": \"report-f9e99fb8\", \"title\": \"科技与产业新政\", \"summary\": \"# 科技与产业新政\\n\\n## 一、事件背景\\n\\n### 事件起因与历史脉络  \\n当前科技与产业政策环境正处于多重结构性变革交汇点：一方面，全球地缘政治博弈持续重塑技术主权边界（如伊朗资产冻结问题折射出金融\", \"sections\": [\"事件背景\", \"现状分析\", \"趋势研判\", \"风险提示\"], \"importance\": 5, \"generatedAt\": \"刚刚\", \"sourceCount\": 0}, {\"id\": \"report-dc01e493\", \"title\": \"科技与投资动态\", \"summary\": \"# 科技与投资动态\\n\\n## 一、事件背景\\n- **事件起因与历史脉络**\\n  - 比亚迪自研芯片的传闻引发了市场广泛关注。比亚迪作为中国领先的新能源汽车制造商，近年来在智能化和电动化方面持续加大投入。\", \"sections\": [\"事件背景\", \"现状分析\", \"趋势研判\", \"风险提示\"], \"importance\": 3, \"generatedAt\": \"刚刚\", \"sourceCount\": 0}, {\"id\": \"report-dc5809dd\", \"title\": \"科技与投资动态\", \"summary\": \"# 科技与投资动态\\n\\n## 一、事件背景\\n- **事件起因与历史脉络**\\n  - 比亚迪自研芯片的传闻引发了市场广泛关注。比亚迪作为中国领先的新能源汽车制造商，近年来在智能化和电动化领域不断加大投入，\", \"sections\": [\"事件背景\", \"现状分析\", \"趋势研判\", \"风险提示\"], \"importance\": 3, \"generatedAt\": \"刚刚\", \"sourceCount\": 0}]', '[{\"icon\": \"💻\", \"items\": [\"科技与产业新政\", \"科技与产业新政\", \"科技与产业新政\"], \"industry\": \"AI与科技\"}]', '{\"hotIndex\": 85, \"hotLabel\": \"高\", \"hotTrend\": \"up\", \"sentiment\": 72, \"volatility\": 45, \"sentimentLabel\": \"偏乐观\", \"sentimentTrend\": \"up\", \"volatilityLabel\": \"低\", \"volatilityTrend\": \"down\"}', '[\"关注关键经济数据发布\", \"关注行业政策动态\", \"关注国际市场变化\"]', NULL, NULL, '2026-05-28 11:05:51', 'published');
